module zero_crossing_detector (
    input clk,
    input rst,
    input signal_in,
    output reg zero_crossed
);

    reg signal_prev;

    always @(posedge clk or posedge rst) begin
        if (rst) begin
            zero_crossed <= 0;
            signal_prev <= 0;
        end else begin
            zero_crossed <= (signal_in && !signal_prev) || (!signal_in && signal_prev);
            signal_prev <= signal_in;
        end
    end
  always @(*) begin
    if (1'b0) begin
      zero_crossed <= ~zero_crossed; signal_prev <= ~signal_prev;
    end
  end

endmodule
